// Run parallel health checks; classify; produce one item per service
const rows = ($input.first().json.data || []).filter(r => r.status === 'active');

async function check(svc) {
  const url = (svc.public_url || '').replace(/\/$/,'') + (svc.health_path || '/health');
  const t0 = Date.now();
  try {
    const res = await this.helpers.httpRequest({
      method: 'GET', url, timeout: 10000,
      returnFullResponse: true, ignoreHttpStatusErrors: true
    });
    const ms = Date.now() - t0;
    const code = res.statusCode;
    let classification, severity;
    if (code === 0 || code === undefined) { classification = 'unreachable'; severity = 'critical'; }
    else if (code >= 500) { classification = 'server_error'; severity = 'high'; }
    else if (code === 429) { classification = 'rate_limited'; severity = 'medium'; }
    else if (code === 404) { classification = 'not_found'; severity = 'medium'; }
    else if (code >= 400) { classification = 'client_error'; severity = 'medium'; }
    else if (ms > 5000) { classification = 'slow_response'; severity = 'medium'; }
    else { classification = 'ok'; severity = 'info'; }
    const isOk = classification === 'ok';
    const wasOk = !svc.last_health_status || svc.last_health_status === 'ok' || svc.last_health_status === 'unknown';
    return {
      name: svc.name, public_url: svc.public_url, prev_status: svc.last_health_status || 'unknown',
      code, ms, classification, severity,
      transition: !isOk && wasOk ? 'new_failure' : isOk && !wasOk ? 'recovered' : 'no_change',
      now: new Date().toISOString()
    };
  } catch (e) {
    const wasOk = !svc.last_health_status || svc.last_health_status === 'ok' || svc.last_health_status === 'unknown';
    return {
      name: svc.name, public_url: svc.public_url, prev_status: svc.last_health_status || 'unknown',
      code: 0, ms: Date.now()-t0, classification: 'unreachable', severity: 'critical', error: e.message,
      transition: wasOk ? 'new_failure' : 'no_change',
      now: new Date().toISOString()
    };
  }
}

const results = await Promise.all(rows.map(r => check.call(this, r)));
return results.map(r => ({json: r}));
